class Solution:
    def vowelStrings(self, words, left, right):
        VOWELS = 'aeiou'
        count = 0
        idx = left
        while idx <= right:
            w = words[idx]
            if w[0] in VOWELS and w[-1] in VOWELS:
                count += 1
            idx += 1
        return count

